// Parse input and build folder_key
const input = $input.first().json;
const body = input.body || input;

const folderType = body.folder_type;
const year = body.year || null;
const month = body.month || null;

// Build folder_key based on type
let folderKey = '';
let folderName = '';

switch (folderType) {
  case 'project_root':
    folderKey = 'project:root';
    folderName = 'Projekte';
    break;
  case 'project_year':
    if (!year) throw new Error('year required for project_year');
    folderKey = `project:${year}`;
    folderName = year;
    break;
  case 'buchhaltung_root':
    folderKey = 'buchhaltung:root';
    folderName = 'VERARBEITET';
    break;
  case 'buchhaltung_year':
    if (!year) throw new Error('year required for buchhaltung_year');
    folderKey = `buchhaltung:${year}`;
    folderName = year;
    break;
  case 'buchhaltung_month':
    if (!year || !month) throw new Error('year and month required for buchhaltung_month');
    folderKey = `buchhaltung:${year}:${month}`;
    folderName = month;
    break;
  default:
    throw new Error(`Unknown folder_type: ${folderType}`);
}

return {
  json: {
    folder_type: folderType,
    folder_key: folderKey,
    folder_name: folderName,
    year: year,
    month: month
  }
};

// Target folder found - return immediately
const lookup = $('🔍 Lookup Target').first().json;
const parsed = $('🔧 Parse Input').first().json;

return {
  json: {
    folder_id: lookup.folder_id,
    full_path: lookup.full_path,
    folder_key: parsed.folder_key,
    folder_type: parsed.folder_type,
    exists: true,
    created: false,
    parent_created: false,
    message: 'Folder found in registry'
  }
};

// Folder found in Drive but not in Registry - register it!
const parsed = $('🔧 Parse Input').first().json;
const parentInfo = $('🔍 Get Parent For Search').first().json;
const driveResult = $('🔎 Search Drive Fallback').first().json;

const foundFolder = driveResult.files[0];

// Build full_path
const fullPath = parentInfo.parent_path 
  ? `${parentInfo.parent_path}/${parsed.folder_name}`
  : parsed.folder_name;

return {
  json: {
    drive_folder_id: foundFolder.id,
    folder_name: foundFolder.name,
    folder_type: parsed.folder_type,
    folder_key: parsed.folder_key,
    parent_folder_id: parentInfo.parent_folder_id,
    full_path: fullPath
  }
};

// Folder was found in Drive, added to registry
const prep = $('🔧 Prepare Register Existing').first().json;

return {
  json: {
    folder_id: prep.drive_folder_id,
    full_path: prep.full_path,
    folder_key: prep.folder_key,
    folder_type: prep.folder_type,
    exists: true,
    created: false,
    parent_created: false,
    registered_from_drive: true,
    message: 'Folder found in Drive, added to registry'
  }
};

// Parent exists - prepare to create target folder
const parsed = $('🔧 Parse Input').first().json;
const parent = $('🔍 Get Parent For Search').first().json;

return {
  json: {
    // Target folder info
    folder_name: parsed.folder_name,
    folder_key: parsed.folder_key,
    folder_type: parsed.folder_type,
    // Parent info
    parent_folder_id: parent.parent_folder_id,
    parent_path: parent.parent_path,
    // Flags
    parent_created: false,
    year: parsed.year,
    month: parsed.month
  }
};

// Parent doesn't exist - need to create it first
// Grandparent (root) should always exist
const parsed = $('🔧 Parse Input').first().json;
const parentInfo = $('🔍 Get Parent For Search').first().json;
const grandparent = $('🔍 Get Grandparent (Root)').first().json;

if (!grandparent.parent_found) {
  throw new Error(`Root folder not found for ${parentInfo.parent_type}. Database seed missing?`);
}

return {
  json: {
    // Parent to create
    parent_type: parentInfo.parent_type,
    parent_key: parentInfo.parent_key,
    parent_name: parsed.year, // Year folders are named by year
    parent_parent_id: grandparent.parent_folder_id,
    parent_parent_path: grandparent.parent_path,
    // Target to create after
    folder_name: parsed.folder_name,
    folder_key: parsed.folder_key,
    folder_type: parsed.folder_type,
    year: parsed.year,
    month: parsed.month
  }
};

// Parent found in Drive - register it and continue
const prep = $('🔧 Prepare Create Parent').first().json;
const driveResult = $('🔎 Search Parent in Drive').first().json;

const foundParent = driveResult.files[0];
const parentPath = prep.parent_parent_path + '/' + prep.parent_name;

return {
  json: {
    // Parent info to register
    parent_drive_id: foundParent.id,
    parent_type: prep.parent_type,
    parent_key: prep.parent_key,
    parent_name: prep.parent_name,
    parent_parent_id: prep.parent_parent_id,
    parent_path: parentPath,
    // Target to create after
    folder_name: prep.folder_name,
    folder_key: prep.folder_key,
    folder_type: prep.folder_type,
    year: prep.year,
    month: prep.month,
    // Flag
    parent_found_in_drive: true
  }
};

// Parent was registered from Drive - now prepare target creation
const prep = $('🔧 Prep Register Parent').first().json;

return {
  json: {
    // Target folder info
    folder_name: prep.folder_name,
    folder_key: prep.folder_key,
    folder_type: prep.folder_type,
    // Parent info (just registered)
    parent_folder_id: prep.parent_drive_id,
    parent_path: prep.parent_path,
    // Flags
    parent_created: false,
    parent_registered_from_drive: true,
    year: prep.year,
    month: prep.month
  }
};

